RY\\n\\nThis workflow is triggered every minute by new emails in Outlook. It first filters for emails that contain binary data (attachments). For such emails, it retrieves the full email content and then proceeds to create a new folder in OneDrive. Concurrently, it splits out the binary data (attachments) from the email. Finally, it merges the information about the newly created OneDrive folder with the attachment data and saves each attachment into the designated OneDrive folder.","height":420,"width":420,"color":5},"id":"927e5e4e-8661-47b7-b98e-35fc446e5590","name":"Sticky Note1","type":"n8n-nodes-base.stickyNote","position":[-576,-528],"typeVersion":1},{"parameters":{"operation":"get","messageId":{"__rl":true,"value":"={{ $('Microsoft Outlook Trigger').item.json.id }}","mode":"id"},"output":"fields","fields":"={{ $('Microsoft Outlook Trigger').item.json.hasAttachments }}","options":{"downloadAttachments":true}},"id":"a48eaa62-522f-47ff-bc8e-7a67cd943db7","name":"Get Outlook Message","type":"n8n-nodes-base.microsoftOutlook","position":[32,112],"webhookId":"fd255a4d-2b30-4883-af8b-b29ba5dbbe88","typeVersion":2,"credentials":{"microsoftOutlookOAuth2Api":{"id":"U00j3CwiwvXfOpLw","name":"Microsoft Outlook account"}}},{"parameters":{"fileName":"={{ $binary[$binary.keys()[0]].fileName }}","parentId":"={{ $node[\\"Outlook Folder Merge\\"].json[\\"id\\"] || $node[\\"Create Folder\\"].json[\\"id\\"] }}","binaryData":true,"binaryPropertyName":"={{ $json.binary }}"},"id":"d4430c49-b48d-4f05-a1f6-ac76add7be2e","name":"Upload File OneDrive","type":"n8n-nodes-base.microsoftOneDrive","position":[896,112],"typeVersion":1,"credentials":{"microsoftOneDriveOAuth2Api":{"id":"lLf5VOXyyqeHeY2U","name":"Microsoft Drive account"}}}]	{"Filter":{"main":[[{"node":"Get Outlook Message","type":"main","index":0}]]},"Split Out":{"main":[[{"node":"Outlook Folder Merge","type":"main","index":1}]]},"Create Folder":{"main":[[{"node":"Outlook Folder Merge","type":"main","index":0}]]},"Get Outlook Me